import type { jsPDF } from "jspdf";

// Noto Sans (SIL Open Font License 1.1), subset to Latin + punctuation + currency symbols
// (incl. the peso sign ₱, U+20B1). jsPDF's built-in Helvetica is Latin-1 only and corrupts
// any string containing ₱, so PDFs embed this Unicode font instead. Subset with fontTools to
// keep the payload small (~26 KB/weight). Registered lazily on the first PDF of a session.
// Source: github.com/googlefonts/noto-fonts (hinted/ttf/NotoSans), OFL — redistributable.

export const PDF_FONT_FAMILY = "NotoSans";

const NOTO_REGULAR_B64 =
    "";

const NOTO_BOLD_B64 =
    "";

// Register the embedded font on a jsPDF instance so setFont(PDF_FONT_FAMILY, "normal"|"bold")
// works. Safe to call once per document.
export function registerPdfFont(doc: jsPDF): void {
    doc.addFileToVFS("NotoSans-Regular.ttf", NOTO_REGULAR_B64);
    doc.addFont("NotoSans-Regular.ttf", PDF_FONT_FAMILY, "normal");
    doc.addFileToVFS("NotoSans-Bold.ttf", NOTO_BOLD_B64);
    doc.addFont("NotoSans-Bold.ttf", PDF_FONT_FAMILY, "bold");
}
